#include <stdio.h>
#include <stdlib.h>
#include <string.h>
int main(){
    // Read entire input
    char *input = NULL;
    size_t size = 0;
    {
        // Determine file size
        fseek(stdin, 0, SEEK_END);
        long fsize = ftell(stdin);
        fseek(stdin, 0, SEEK_SET);
        if (fsize < 0) fsize = 0;
        input = (char*)malloc(fsize + 2);
        if (!input) return 0;
        size_t read = fread(input, 1, fsize, stdin);
        input[read] = '\0';
    }
    // Replace escaped "\\n" with real newlines
    char *processed = (char*)malloc(strlen(input) + 1);
    if (!processed) return 0;
    size_t j = 0;
    for (size_t i = 0; input[i]; ++i) {
        if (input[i] == '\\' && input[i+1] == 'n') {
            processed[j++] = '\n';
            ++i; // skip 'n'
        } else {
            processed[j++] = input[i];
        }
    }
    processed[j] = '\0';
    // Now parse
    int T = 0;
    char *ptr = processed;
    sscanf(ptr, "%d", &T);
    // Move pointer past the first line
    while (*ptr && *ptr != '\n') ++ptr;
    if (*ptr == '\n') ++ptr;
    for (int t = 0; t < T; ++t) {
        char s[1005];
        int i = 0;
        while (ptr[i] && ptr[i] != '\n' && i < 1004) {
            s[i] = ptr[i];
            ++i;
        }
        s[i] = '\0';
        ptr += i;
        if (*ptr == '\n') ++ptr;
        int sum = 0;
        for (int k = 0; s[k]; ++k) {
            if (s[k] >= '0' && s[k] <= '9') sum += s[k] - '0';
        }
        if (t + 1 < T) {
            printf("%d\\n", sum);
        } else {
            printf("%d", sum);
        }
    }
    free(input);
    free(processed);
    return 0;
}

