#include <bits/stdc++.h>
using namespace std;
int main(){
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    // Read whole input
    string raw((istreambuf_iterator<char>(cin)), istreambuf_iterator<char>());
    // Replace escaped \n with actual newline
    string processed;
    processed.reserve(raw.size());
    for (size_t i = 0; i < raw.size(); ++i) {
        if (raw[i] == '\\' && i + 1 < raw.size() && raw[i+1] == 'n') {
            processed.push_back('\n');
            ++i; // skip 'n'
        } else {
            processed.push_back(raw[i]);
        }
    }
    stringstream ss(processed);
    int T; ss >> T;
    string s;
    vector<string> results;
    for (int t = 0; t < T; ++t) {
        ss >> s; // strings contain no spaces
        int sum = 0;
        for (char c : s) if (c >= '0' && c <= '9') sum += c - '0';
        results.push_back(to_string(sum));
    }
    for (size_t i = 0; i < results.size(); ++i) {
        cout << results[i];
        if (i + 1 < results.size()) cout << "\\n";
    }
    return 0;
}

code.Java:
import java.io.*;
import java.util.*;
public class Main {
    public static void main(String[] args) throws IOException {
        // Read entire input as a single string
        StringBuilder sb = new StringBuilder();
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        int ch;
        while ((ch = br.read()) != -1) {
            sb.append((char) ch);
        }
        String raw = sb.toString();
        // Replace escaped \n with real newline
        String processed = raw.replaceAll("\\\\n", "\n");
        StringTokenizer st = new StringTokenizer(processed, "\n");
        int T = Integer.parseInt(st.nextToken().trim());
        StringBuilder out = new StringBuilder();
        for (int t = 0; t < T; ++t) {
            String s = st.nextToken(); // each test case string
            int sum = 0;
            for (int i = 0; i < s.length(); ++i) {
                char c = s.charAt(i);
                if (c >= '0' && c <= '9') sum += c - '0';
            }
            out.append(sum);
            if (t + 1 < T) out.append("\\n");
        }
        System.out.print(out.toString());
    }
}

