const fs = require('fs');
let raw = fs.readFileSync(0, 'utf8');
// Replace escaped \n with real newlines
let processed = raw.replace(/\\n/g, '\n');
let lines = processed.split('\n');
let idx = 0;
const T = parseInt(lines[idx++].trim(), 10);
let results = [];
for (let t = 0; t < T; ++t) {
    const s = (lines[idx++] || '').trim();
    let sum = 0;
    for (const ch of s) {
        if (ch >= '0' && ch <= '9') sum += ch.charCodeAt(0) - 48;
    }
    results.push(String(sum));
}
process.stdout.write(results.join('\\n'));
